    public String encrypt(String plainText) {
        if (plainText == null || plainText.isEmpty()) return plainText;
        
        try {
            Cipher cipher = Cipher.getInstance(AES_MODE);
            cipher.init(Cipher.ENCRYPT_MODE, secretKey);
            
            byte[] iv = cipher.getIV();
            byte[] encrypted = cipher.doFinal(plainText.getBytes("UTF-8"));
            
            prefs.edit().putString(IV_PREF_KEY, Base64.encodeToString(iv, Base64.DEFAULT)).apply();
            
            return Base64.encodeToString(encrypted, Base64.DEFAULT);
        } catch (Exception e) {
            Log.e(TAG, "Encryption error", e);
            return null;
        }
    }
    
    public String decrypt(String encryptedText) {
        if (encryptedText == null || encryptedText.isEmpty()) return encryptedText;
        
        try {
            Cipher cipher = Cipher.getInstance(AES_MODE);
            byte[] iv = Base64.decode(prefs.getString(IV_PREF_KEY, ""), Base64.DEFAULT);
            IvParameterSpec ivSpec = new IvParameterSpec(iv);
            cipher.init(Cipher.DECRYPT_MODE, secretKey, ivSpec);
            
            byte[] decrypted = cipher.doFinal(Base64.decode(encryptedText, Base64.DEFAULT));
            return new String(decrypted, "UTF-8");
        } catch (Exception e) {
            Log.e(TAG, "Decryption error", e);
            return null;
        }
    }
    
